   109→function normalizeCategory(input: string | undefined): SubmissionCategory | null {
   110→  if (!input) return null;
   111→  const raw = input.trim();
   112→  if (raw === "FUEL") return "fuel_station";
   113→  if (raw === "MOBILE_MONEY" || raw === "KIOSK") return "mobile_money";
   114→  if (raw === "PHARMACY") return "pharmacy";
   115→  if (raw === "fuel_station" || raw === "mobile_money" || raw === "pharmacy") return raw;
