   171→  const base64 = stripBase64Prefix(imageBase64);
   172→  const imageBuffer = Buffer.from(base64, "base64");
   173→  if (!imageBuffer.length) return null;
   174→
   175→  return { imageBuffer, mime, ext: mimeToExtension(mime) };
   176→}
