   252→function getUserDisplayName(userId: string, name: string | null, email: string | null): string {
   253→  if (name && name.trim()) return name.trim();
   254→  if (email) {
   255→    const atIndex = email.indexOf("@");
   256→    if (atIndex > 0) return email.slice(0, atIndex);
   257→    return email;
   258→  }
   259→  return userId || "Contributor";
