   473→  const clientDevice = sanitizeClientDevice((details as Record<string, unknown>).clientDevice);
   474→  if (clientDevice) {
   475→    if (!clientDevice.userAgent && requestUserAgent) clientDevice.userAgent = requestUserAgent;
