   160→async function upsertUserProfileLegacy(params: {
   161→  id: string;
   162→  email: string | null;
   163→  name: string;
   164→  image: string;
   165→  occupation: string;
   166→  xp: number;
   167→  passwordHash: string | null;
   168→  isAdmin: boolean;
   169→  mapScope: MapScope;
