   172→  if (!legacyEmail) {
   173→    throw new Error("Database migration required: phone-only identifiers need user_profiles.phone column");
   174→  }
   175→
   176→  await query(
   177→    `
   178→      insert into user_profiles (id, email, name, image, occupation, xp, password_hash, is_admin, map_scope, updated_at)
   179→      values ($1, $2, $3, $4, $5, $6, $7, $8, $9, now())
   180→      on conflict (id) do update
   181→      set
   182→        email = excluded.email,
   183→        name = excluded.name,
   184→        image = excluded.image,
   185→        occupation = excluded.occupation,
   186→        xp = excluded.xp,
   187→        password_hash = coalesce(excluded.password_hash, user_profiles.password_hash),
   188→        is_admin = excluded.is_admin,
   189→        map_scope = excluded.map_scope,
   190→        updated_at = now()
   191→    `,
   192→    [
   193→      params.id,
   194→      legacyEmail,
   195→      params.name,
   196→      params.image,
   197→      params.occupation,
   198→      params.xp,
   199→      params.passwordHash,
   200→      params.isAdmin,
   201→      params.mapScope,
   202→    ],
   203→  );
   204→}
