   269→async function insertPointEvent(event: PointEvent): Promise<void> {
   270→  const id = normalizeEventId(event.id);
   271→  const pointId = typeof event.pointId === "string" && event.pointId.trim() ? event.pointId.trim() : id;
   272→  const eventType = parseEventType(event.eventType);
   273→  const userId = normalizeUserId(event.userId || "unknown");
   274→  const category = parseCategory(event.category);
   275→  const location = parseLocation(event.location);
   276→  if (!location) throw new Error("Invalid point event location");
   277→  const details = event.details && typeof event.details === "object" ? event.details : {};
   278→  const photoUrl = typeof event.photoUrl === "string" ? event.photoUrl : null;
   279→  const createdAt = normalizeCreatedAt(event.createdAt);
   280→  const source = typeof event.source === "string" ? event.source : null;
   281→  const externalId = typeof event.externalId === "string" ? event.externalId : null;
   282→
   283→  await query(
   284→    `
   285→      insert into point_events (id, point_id, event_type, user_id, category, latitude, longitude, details, photo_url, created_at, source, external_id)
   286→      values ($1::uuid, $2, $3, $4, $5, $6, $7, $8::jsonb, $9, $10::timestamptz, $11, $12)
   287→      on conflict (id) do update
   288→      set
   289→        point_id = excluded.point_id,
   290→        event_type = excluded.event_type,
   291→        user_id = excluded.user_id,
   292→        category = excluded.category,
   293→        latitude = excluded.latitude,
   294→        longitude = excluded.longitude,
   295→        details = excluded.details,
   296→        photo_url = excluded.photo_url,
   297→        created_at = excluded.created_at,
   298→        source = excluded.source,
   299→        external_id = excluded.external_id
   300→    `,
   301→    [id, pointId, eventType, userId, category, location.latitude, location.longitude, JSON.stringify(details), photoUrl, createdAt, source, externalId],
   302→  );
   303→}
   304→
   305→async function deletePointEvent(eventId: string): Promise<boolean> {
   306→  const normalizedId = normalizeEventId(eventId);
   307→  const result = await query(
   308→    `
   309→      delete from point_events
   310→      where id = $1::uuid
   311→    `,
   312→    [normalizedId],
   313→  );
   314→  return result.rowCount > 0;
   315→}
   316→
   317→async function bulkUpsertPointEvents(events: PointEvent[]): Promise<void> {
   318→  if (!events.length) return;
   319→
   320→  await query("begin");
   321→  try {
   322→    for (const event of events) {
   323→      await insertPointEvent(event);
   324→    }
   325→    await query("commit");
   326→  } catch (error) {
   327→    await query("rollback");
   328→    throw error;
   329→  }
   330→}
