   252→export function legacySubmissionToCreateEvent(submission: LegacySubmission): PointEvent {
   253→  const eventType: PointEventType = "CREATE_EVENT";
   254→  const details = normalizeDetailsForCategory(submission.category, submission.details ?? {});
   255→  const source = trimString(details.source) ?? "legacy_submission";
   256→  const externalId = trimString(details.externalId) ?? `legacy:${submission.id}`;
   257→  return {
   258→    id: `legacy-event-${submission.id}`,
   259→    pointId: submission.id,
   260→    eventType,
   261→    userId: submission.userId,
   262→    category: submission.category,
   263→    location: submission.location,
   264→    details,
   265→    photoUrl: submission.photoUrl,
   266→    createdAt: submission.createdAt,
   267→    source,
   268→    externalId,
   269→  };
   270→}
   271→
   272→export function mergePointEventsWithLegacy(pointEvents: PointEvent[], legacySubmissions: LegacySubmission[]): PointEvent[] {
   273→  const merged = [...pointEvents];
   274→  const seen = new Set(merged.map((item) => item.id));
   275→  for (const legacy of legacySubmissions) {
   276→    const converted = legacySubmissionToCreateEvent(legacy);
   277→    if (seen.has(converted.id)) continue;
   278→    merged.push(converted);
   279→    seen.add(converted.id);
   280→  }
   281→  return merged;
   282→}
